refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/opencv_smarties.png"));
image = imresize(image, [240 320]);
model = image(55:120, 90:160, :);
score = imbackproject(image, model, 32);
scoreView = round(immat2gray(score) * 63) + 1;
subplot(1, 2, 1);
imshow(image);
subplot(1, 2, 2);
imshow(scoreView, hot(64));
